// Classic: factorial
function factorial(n: number): number {
  if (n <= 1) return 1; // base case
  return n * factorial(n - 1); // recursive case
}

// Flatten nested array (arbitrary depth)
function flattenDeep(arr: unknown[]): unknown[] {
  return arr.reduce<unknown[]>((acc, val) => {
    return Array.isArray(val)
      ? acc.concat(flattenDeep(val))
      : acc.concat(val);
  }, []);
}

// Deep clone with recursion
function deepClone<T>(obj: T): T {
  if (obj === null || typeof obj !== 'object') return obj;
  if (Array.isArray(obj)) return obj.map(deepClone) as T;
  return Object.fromEntries(
    Object.entries(obj as Record<string, unknown>).map(([k, v]) => [k, deepClone(v)])
  ) as T;
}

// Power set (all subsets) — backtracking pattern
function powerSet<T>(arr: T[]): T[][] {
  if (arr.length === 0) return [[]];
  const [first, ...rest] = arr;
  const withoutFirst = powerSet(rest);
  const withFirst = withoutFirst.map((subset) => [first, ...subset]);
  return [...withoutFirst, ...withFirst];
}

